// Model catalog — Quaternius CC0 + KayKit Forest Nature Pack GLTF models
// Organized by category for the world builder palette

export type ModelCategory =
  | 'buildings_residential'
  | 'buildings_civic'
  | 'buildings_military'
  | 'buildings_economy'
  | 'buildings_special'
  | 'nature_trees'
  | 'nature_bushes'
  | 'nature_plants'
  | 'nature_grass'
  | 'nature_rocks'
  | 'nature_terrain'
  | 'nature_water'
  | 'ground_tiles'
  | 'blocks'
  | 'columns'
  | 'animals'
  | 'characters'
  | 'characters_extended'
  | 'characters_special'
  | 'platforms'
  | 'vehicles'
  | 'props_scifi'
  | 'props_containers'
  | 'props_weapons'
  | 'props_items'
  | 'props_nautical'
  | 'infrastructure';

export interface CatalogModel {
  id:           string;
  label:        string;
  url:          string;
  category:     ModelCategory;
  defaultScale: number;
  yOffset:      number;
  emoji:        string;
  isBuilding?:  boolean;   // shows on map, generates trail
  tags?:        string[];  // searchable tags
}

const G  = (name: string) => `/models/gltf/${name}.gltf`;
const GLB = (name: string) => `/models/gltf/${name}.glb`;

